#include<bits/stdc++.h>
#define N 12000005
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=1;
	while(ch<'0'||ch>'9'){if(ch=='-')flag=0;ch=getchar();}
	while(ch>='0'&&ch<='9')res=res*10+(ch^48),ch=getchar();
	return flag?res:-res;
}
int bin[N],top;
struct FHQ{int l,r,s,val,siz,key,tag,sum;}t[N];
int T1,T2,T3,T4,T5,cnt,crt,rt[N],las;
inline void check()
{
	puts("--------");
	puts("    l r val sum");
	for(int i=1;i<=cnt;++i)
	{
		printf("%d : %d %d %d   %d\n",i,t[i].l,t[i].r,t[i].val,t[i].sum);
	}
	printf("Root:  %d\n",rt[crt]);
	puts("--------");
}
inline int node(int k)
{
	t[++cnt].siz=1;t[cnt].val=t[cnt].sum=k;
	t[cnt].key=rand();return cnt;
}
inline void update(int k)
{
	t[k].siz=t[t[k].l].siz+t[t[k].r].siz+1;
	t[k].sum=t[t[k].l].sum+t[t[k].r].sum+t[k].val;
}
inline int copy(int k)
{
	int x;if(!top)x=++cnt;else 
	{
		x=bin[top--];
		if(t[x].l)bin[++top]=t[x].l;
		if(t[x].r)bin[++top]=t[x].r;
	}
	t[x]=t[k];return x;
}
inline void push_down(int k)
{
	if(!t[k].tag) { return; }
	if(t[k].l)t[k].l=copy(t[k].l);
	if(t[k].r)t[k].r=copy(t[k].r);
	swap(t[k].l,t[k].r);
	if(t[k].l)t[t[k].l].tag^=1;
	if(t[k].r)t[t[k].r].tag^=1;
	t[k].tag=0;
}
