inline void split(int k,int cur,int &x,int &y)
{
	if(!cur){x=y=0;return;}
	push_down(cur);
	int ls=t[t[cur].l].siz;
	if(ls<k)
	{
		x=copy(cur);
		split(k-ls-1,t[x].r,t[x].r,y);
		update(x);
	}
	else
	{
		y=copy(cur);
		split(k,t[y].l,x,t[y].l);
		update(y);
	}
}
inline int merge(int L,int R)
{
	if(!L||!R){return L+R;}
	push_down(L);push_down(R);
	if(t[L].key<=t[R].key)
	{
		t[L].r=merge(t[L].r,R);
		update(L);return L;
	}
	else
	{
		t[R].l=merge(L,t[R].l);
		update(R);return R;
	}
}
inline void ins(int p,int x,int Root)
{
	split(p,Root,T1,T2);
//	check();
	rt[++crt]=merge(merge(T1,node(x)),T2);
//	printf("Root: %d\n\n",rt[crt]);
}
inline void del(int p,int Root)
{
	split(p,Root,T1,T2);
	split(p-1,T1,T1,T3);
	rt[++crt]=merge(T1,T2);
	bin[++top]=T3;
}
inline void rev(int l,int r,int Root)
{
	split(r,Root,T1,T2);
	split(l-1,T1,T1,T3);
	t[T3].tag^=1;
	rt[++crt]=merge(merge(T1,T3),T2);
}
inline void fnd(int l,int r,int Root)
{
	split(r,Root,T1,T2);
	split(l-1,T1,T1,T3);
	printf("%lld\n",t[T3].sum);
	las=t[T3].sum;
	rt[++crt]=merge(merge(T1,T3),T2);
}

signed main()
{
//	freopen("data.txt","r",stdin);
	int n=read();las=0;while(n--)
	{
		int typ=read(),opt=read(),l=read()^las;
		switch(opt)
		{
			case 1: ins(l,read()^las,rt[typ]);break;
			case 2: del(l,rt[typ]); /* ___ */ break;
			case 3: rev(l,read()^las,rt[typ]);break;
			case 4: fnd(l,read()^las,rt[typ]);break;
		}
//		check();
	}
}
